{"type": "email", "id": "email_001", "subject": "Weekly Team Meeting Update", "from": "ryan.cooper@mediconnsolutions.com", "from_name": "Ryan Cooper", "to": ["michelle.parker@mediconnsolutions.com", "james.watson@mediconnsolutions.com", "sarah.martin@mediconnsolutions.com", "paul.johnson@mediconnsolutions.com", "lisa.davis@mediconnsolutions.com", "mark.brown@mediconnsolutions.com"], "cc": [], "date": "2022-05-01 09:00:00", "body": "Dear team,

