{"type": "email", "id": "email_002", "subject": "Q2 Budget Planning", "from": "james.watson@mediconnsolutions.com", "from_name": "James Watson", "to": ["ryan.cooper@mediconnsolutions.com", "mark.brown@mediconnsolutions.com", "paul.johnson@mediconnsolutions.com"], "cc": [], "date": "2022-05-02 11:00:00", "body": "Hi team,

