{"type": "email", "id": "email_004", "subject": "Performance Review Timeline", "from": "sarah.martin@mediconnsolutions.com", "from_name": "Sarah Martin", "to": ["ryan.cooper@mediconnsolutions.com", "michelle.parker@mediconnsolutions.com", "james.watson@mediconnsolutions.com", "paul.johnson@mediconnsolutions.com", "lisa.davis@mediconnsolutions.com", "mark.brown@mediconnsolutions.com"], "cc": [], "date": "2022-05-04 16:00:00", "body": "Dear all,

